class MagicDictionary:
    def __init__(self):
        self.words = []
    def buildDict(self, dictionary):
        self.words = list(dictionary)
    def search(self, searchWord):
        for w in self.words:
            if len(w) != len(searchWord):
                continue
            diff = sum(1 for a, b in zip(w, searchWord) if a != b)
            if diff == 1:
                return True
        return False

