class MagicDictionary:
    def __init__(self):
        self.by_len = {}
    def buildDict(self, dictionary):
        self.by_len = {}
        for w in dictionary:
            self.by_len.setdefault(len(w), []).append(w)
    def search(self, searchWord):
        for w in self.by_len.get(len(searchWord), []):
            diff = 0
            for a, b in zip(w, searchWord):
                if a != b:
                    diff += 1
                    if diff > 1:
                        break
            if diff == 1:
                return True
        return False

